import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function LogStream({ logs, onPause, isPaused }) {
  const { div, pre, span } = tags;
  let containerRef;
  const [isHovered, setIsHovered] = createSignal(false);

  const levelColors = {
    DEBUG: '#666666',
    INFO: '#00FF00',
    WARN: '#FFB000',
    ERROR: '#FF0000'
  };

  const scrollToBottom = () => {
    if (!isHovered() && !isPaused) {
      containerRef?.scrollTo({ top: containerRef.scrollHeight });
    }
  };

  onMount(() => {
    const interval = setInterval(scrollToBottom, 100);
    return () => clearInterval(interval);
  });

  return div({ class: css('term-panel _flex _col _hfull') },
    div({ class: css('_flex _aic _jcsb _p2 _borderB _bordercolor[#333]') },
      span({ class: css('_textsm') }, `Showing ${logs.length} entries`),
      Button({ variant: 'ghost', size: 'sm', onclick: onPause },
        icon(isPaused ? 'play' : 'pause'), isPaused ? ' Resume' : ' Pause'
      )
    ),
    pre({
      ref: (el) => containerRef = el,
      class: css('_flex1 _overflow[auto] _m0 _p2'),
      onmouseenter: () => setIsHovered(true),
      onmouseleave: () => setIsHovered(false)
    },
      ...logs.map(log =>
        div({ class: css('_flex _gap2 _textsm') },
          span({ class: css('_fgmuted _w[80px]') }, log.timestamp),
          span({ style: `color: ${levelColors[log.level]}; width: 48px` }, `[${log.level}]`),
          span({ class: css('_fgmuted _w[100px] _truncate') }, log.source),
          span({}, log.message)
        )
      )
    )
  );
}

