function FilteredLogStream({ logs }) {
  const { div, input, span, label } = tags;
  const [filters, setFilters] = createSignal({ DEBUG: true, INFO: true, WARN: true, ERROR: true });
  const [search, setSearch] = createSignal('');

  const filteredLogs = () => logs.filter(log =>
    filters()[log.level] && log.message.toLowerCase().includes(search().toLowerCase())
  );

  const toggleFilter = (level) => setFilters({ ...filters(), [level]: !filters()[level] });

  return div({ class: css('term-panel _flex _col _hfull') },
    div({ class: css('_flex _aic _gap4 _p2 _borderB _bordercolor[#333]') },
      input({
        type: 'text',
        placeholder: 'Search logs...',
        value: search,
        oninput: (e) => setSearch(e.target.value),
        class: css('_flex1 _bg[transparent] _border _bordercolor[#333] _p1 _fggreen _mono')
      }),
      ...['DEBUG', 'INFO', 'WARN', 'ERROR'].map(level =>
        label({ class: css('_flex _aic _gap1 _cursor[pointer]') },
          input({ type: 'checkbox', checked: filters()[level], onchange: () => toggleFilter(level) }),
          span({}, level)
        )
      )
    ),
    LogStream({ logs: filteredLogs(), isPaused: false })
  );
}

