function GroupedLogStream({ logs, groupBy = 'source' }) {
  const { div, details, summary, span } = tags;

  const grouped = logs.reduce((acc, log) => {
    const key = log[groupBy];
    if (!acc[key]) acc[key] = [];
    acc[key].push(log);
    return acc;
  }, {});

  return div({ class: css('term-panel _hfull _overflow[auto] _p2') },
    ...Object.entries(grouped).map(([group, entries]) =>
      details({ class: css('_mb2'), open: true },
        summary({ class: css('_cursor[pointer] _p1 _bgmuted/10') },
          span({}, `${group} (${entries.length})`)
        ),
        ...entries.map(log => div({ class: css('_pl4 _textsm') }, log.message))
      )
    )
  );
}

